def bubble_sort(a):
    n = len(a)
    for i in range(n - 1):
        swapped = False
        for j in range(n - 1 - i):
            if a[j] > a[j + 1]:
                a[j], a[j + 1] = a[j + 1], a[j]
                swapped = True
        if not swapped:
            break
    return a

# Example usage:
data = [64, 34, 25, 12, 22, 11, 90]
print(bubble_sort(data))  # Output: [11, 12, 22, 25, 34, 64, 90]

def selection_sort(a):
    n = len(a)
    for i in range(n - 1):
        min_idx = i
        for j in range(i + 1, n):
            if a[j] < a[min_idx]:
                min_idx = j
        if min_idx != i:
            a[i], a[min_idx] = a[min_idx], a[i]
    return a

# Example usage:
data = [64, 25, 12, 22, 11]
print(selection_sort(data))  # Output: [11, 12, 22, 25, 64]
